namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
    public string Office { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Location { get; set; } = "";
    public int DepartmentId { get; set; }
    public int InstructorId { get; set; }
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{1,3}\d{5,8}$", ErrorMessage = "Student ID must be 1-3 uppercase letters followed by 5-8 digits (e.g., CS12345).")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }

    public string? Comments { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of abstract structures, quantities, and patterns through rigorous logical reasoning." },
            new() { Id = 3, Code = "ENGL", Name = "English", Description = "Analysis and creation of literary and expository texts, with emphasis on critical thinking and communication." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces that govern the natural world." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning with over 15 years of teaching experience.", Email = "achen@university.edu", Office = "Science Hall 301" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Computer Science", Bio = "Dr. Martinez focuses on software engineering and distributed systems. He has published extensively on microservice architectures.", Email = "rmartinez@university.edu", Office = "Science Hall 305" },
            new() { Id = 3, Name = "Dr. Sarah Patel", Title = "Professor of Mathematics", Bio = "Dr. Patel is an expert in applied mathematics and statistics, with research interests in stochastic modeling.", Email = "spatel@university.edu", Office = "Math Building 210" },
            new() { Id = 4, Name = "Dr. James O'Brien", Title = "Associate Professor of English", Bio = "Dr. O'Brien is a published novelist and literary critic specializing in modern American literature.", Email = "jobrien@university.edu", Office = "Humanities Hall 104" },
            new() { Id = 5, Name = "Dr. Emily Nakamura", Title = "Professor of Physics", Bio = "Dr. Nakamura conducts research in quantum mechanics and has been recognized with multiple teaching awards.", Email = "enakamura@university.edu", Office = "Physics Building 402" },
            new() { Id = 6, Name = "Dr. David Kim", Title = "Associate Professor of Mathematics", Bio = "Dr. Kim specializes in discrete mathematics and combinatorics with applications in computer science.", Email = "dkim@university.edu", Office = "Math Building 215" }
        };

        _courses = new List<Course>
        {
            // Computer Science (4 courses)
            new() { Id = 1, Code = "CS101", Title = "Introduction to Computer Science", Description = "Foundational course covering programming fundamentals, data types, control structures, and basic algorithms using Python.", Credits = 3, Schedule = "Mon/Wed 9:00–10:15 AM", Location = "Science Hall 110", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS201", Title = "Data Structures and Algorithms", Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and searching algorithms with complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", Location = "Science Hall 112", DepartmentId = 1, InstructorId = 2, IsFeatured = false },
            new() { Id = 3, Code = "CS301", Title = "Software Engineering", Description = "Principles of software development including agile methodologies, version control, testing, and project management.", Credits = 3, Schedule = "Mon/Wed 1:00–2:15 PM", Location = "Science Hall 205", DepartmentId = 1, InstructorId = 2, IsFeatured = true },
            new() { Id = 4, Code = "CS401", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search, knowledge representation, machine learning, and neural networks.", Credits = 4, Schedule = "Tue/Thu 2:30–3:45 PM", Location = "Science Hall 310", DepartmentId = 1, InstructorId = 1, IsFeatured = false },

            // Mathematics (3 courses)
            new() { Id = 5, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications in science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM", Location = "Math Building 101", DepartmentId = 2, InstructorId = 3, IsFeatured = true },
            new() { Id = 6, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Location = "Math Building 103", DepartmentId = 2, InstructorId = 6, IsFeatured = false },
            new() { Id = 7, Code = "MATH301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 2:30–3:45 PM", Location = "Math Building 201", DepartmentId = 2, InstructorId = 3, IsFeatured = false },

            // English (3 courses)
            new() { Id = 8, Code = "ENGL101", Title = "Composition and Rhetoric", Description = "Development of academic writing skills including argumentation, research methods, and critical analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Humanities Hall 201", DepartmentId = 3, InstructorId = 4, IsFeatured = false },
            new() { Id = 9, Code = "ENGL201", Title = "American Literature", Description = "Survey of major works in American literature from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", Location = "Humanities Hall 203", DepartmentId = 3, InstructorId = 4, IsFeatured = true },
            new() { Id = 10, Code = "ENGL305", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry writing with peer review and revision practice.", Credits = 3, Schedule = "Wed 3:00–5:30 PM", Location = "Humanities Hall 105", DepartmentId = 3, InstructorId = 4, IsFeatured = false },

            // Physics (2 courses)
            new() { Id = 11, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves with laboratory component. Calculus-based approach.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Physics Building 100", DepartmentId = 4, InstructorId = 5, IsFeatured = true },
            new() { Id = 12, Code = "PHYS201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics with laboratory component.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:15 PM", Location = "Physics Building 100", DepartmentId = 4, InstructorId = 5, IsFeatured = false }
        };
    }

    public IReadOnlyList<Department> GetDepartments() => _departments.AsReadOnly();

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses() => _courses.AsReadOnly();

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList().AsReadOnly();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList().AsReadOnly();

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList().AsReadOnly();

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course is not null ? GetDepartment(course.DepartmentId) : null;
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

