@page "/"

@inject CatalogService CatalogService

<PageTitle>Course Catalog - Home</PageTitle>

<div class="hero-section text-center">
    <h1>University Course Catalog</h1>
    <p class="lead">Explore our diverse range of courses and find the perfect fit for your academic journey.</p>
    <a href="courses" class="btn btn-light btn-lg mt-2">Browse All Courses</a>
